using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Store.Tests;

[TestClass]
public sealed class ShoppingCartTests
{
    private ShoppingCart _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _sut = new ShoppingCart();
    }

    // ───────────────────────────── AddItem – Happy Path ─────────────────────────────

    [TestMethod]
    public void AddItem_SingleItem_IncreasesTotal()
    {
        // Arrange & Act
        _sut.AddItem("SKU-001", 2, 10.00m);

        // Assert
        Assert.AreEqual(20.00m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_MultipleDistinctItems_SumsCorrectly()
    {
        // Act
        _sut.AddItem("SKU-001", 1, 10.00m);
        _sut.AddItem("SKU-002", 3, 5.00m);

        // Assert
        Assert.AreEqual(25.00m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_DuplicateSku_AccumulatesQuantity()
    {
        // Act
        _sut.AddItem("SKU-001", 2, 10.00m);
        _sut.AddItem("SKU-001", 3, 10.00m);

        // Assert – 5 × 10 = 50
        Assert.AreEqual(50.00m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_ZeroPrice_AllowedAndTotalIsZero()
    {
        // Act
        _sut.AddItem("FREE-ITEM", 5, 0.00m);

        // Assert
        Assert.AreEqual(0.00m, _sut.CalculateTotal());
    }

    // ───────────────────────────── AddItem – Error Cases ─────────────────────────────

    [TestMethod]
    [DataRow(null, DisplayName = "Null SKU")]
    [DataRow("", DisplayName = "Empty SKU")]
    public void AddItem_NullOrEmptySku_ThrowsArgumentException(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(() => _sut.AddItem(sku!, 1, 10.00m));
    }

    [TestMethod]
    [DataRow(0, DisplayName = "Zero quantity")]
    [DataRow(-1, DisplayName = "Negative quantity")]
    public void AddItem_NonPositiveQuantity_ThrowsArgumentException(int quantity)
    {
        Assert.ThrowsException<ArgumentException>(() => _sut.AddItem("SKU-001", quantity, 10.00m));
    }

    [TestMethod]
    public void AddItem_NegativePrice_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(() => _sut.AddItem("SKU-001", 1, -1.00m));
    }

    // ───────────────────────────── RemoveItem – Happy Path ─────────────────────────────

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovesFromCart()
    {
        // Arrange
        _sut.AddItem("SKU-001", 2, 10.00m);
        _sut.AddItem("SKU-002", 1, 5.00m);

        // Act
        _sut.RemoveItem("SKU-001");

        // Assert – only SKU-002 remains
        Assert.AreEqual(5.00m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_OnlyItem_CartBecomesEmpty()
    {
        // Arrange
        _sut.AddItem("SKU-001", 1, 10.00m);

        // Act
        _sut.RemoveItem("SKU-001");

        // Assert
        Assert.AreEqual(0.00m, _sut.CalculateTotal());
    }

    // ───────────────────────────── RemoveItem – Error Cases ─────────────────────────────

    [TestMethod]
    [DataRow(null, DisplayName = "Null SKU")]
    [DataRow("", DisplayName = "Empty SKU")]
    public void RemoveItem_NullOrEmptySku_ThrowsArgumentException(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(() => _sut.RemoveItem(sku!));
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_ThrowsInvalidOperationException()
    {
        Assert.ThrowsException<InvalidOperationException>(() => _sut.RemoveItem("GHOST"));
    }

    // ───────────────────────────── CalculateTotal ─────────────────────────────

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0.00m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterAddAndRemove_ReflectsCurrentItems()
    {
        // Arrange
        _sut.AddItem("A", 2, 10.00m);
        _sut.AddItem("B", 1, 7.50m);
        _sut.RemoveItem("A");

        // Assert
        Assert.AreEqual(7.50m, _sut.CalculateTotal());
    }

    // ───────────────────────────── ApplyCoupon – Happy Path ─────────────────────────────

    [TestMethod]
    [DataRow("SAVE10", 90.00, DisplayName = "10% off 100")]
    [DataRow("SAVE20", 80.00, DisplayName = "20% off 100")]
    [DataRow("FLAT5", 95.00, DisplayName = "$5 off 100")]
    public void ApplyCoupon_ValidCode_AppliesDiscount(string code, double expectedDouble)
    {
        // Arrange
        var expected = (decimal)expectedDouble;
        _sut.AddItem("SKU-001", 10, 10.00m); // total = 100

        // Act
        _sut.ApplyCoupon(code);

        // Assert
        Assert.AreEqual(expected, _sut.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_Flat5ExceedsTotal_ReturnsZero()
    {
        // Arrange – total = 3
        _sut.AddItem("CHEAP", 1, 3.00m);

        // Act
        _sut.ApplyCoupon("FLAT5");

        // Assert
        Assert.AreEqual(0.00m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_Save10_OnEmptyCart_ReturnsZero()
    {
        // Act
        _sut.ApplyCoupon("SAVE10");

        // Assert
        Assert.AreEqual(0.00m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_ReplacePreviousCoupon_UsesLatest()
    {
        // Arrange
        _sut.AddItem("SKU-001", 10, 10.00m); // total = 100

        // Act
        _sut.ApplyCoupon("SAVE10"); // 90
        _sut.ApplyCoupon("SAVE20"); // should now be 80, not 72

        // Assert
        Assert.AreEqual(80.00m, _sut.CalculateTotal());
    }

    // ───────────────────────────── ApplyCoupon – Error Cases ─────────────────────────────

    [TestMethod]
    [DataRow(null, DisplayName = "Null code")]
    [DataRow("", DisplayName = "Empty code")]
    public void ApplyCoupon_NullOrEmptyCode_ThrowsArgumentException(string? code)
    {
        Assert.ThrowsException<ArgumentException>(() => _sut.ApplyCoupon(code!));
    }

    [TestMethod]
    [DataRow("INVALID", DisplayName = "Unknown code")]
    [DataRow("save10", DisplayName = "Wrong case")]
    [DataRow("SAVE30", DisplayName = "Non-existent tier")]
    public void ApplyCoupon_InvalidCode_ThrowsArgumentException(string code)
    {
        Assert.ThrowsException<ArgumentException>(() => _sut.ApplyCoupon(code));
    }

    // ───────────────────────────── Integration-style scenarios ─────────────────────────────

    [TestMethod]
    public void FullWorkflow_AddRemoveCouponTotal_ProducesCorrectResult()
    {
        // Add items
        _sut.AddItem("WIDGET", 3, 12.00m);  // 36
        _sut.AddItem("GADGET", 2, 25.00m);  // 50
        _sut.AddItem("GIZMO", 1, 14.00m);   // 14
        // Total = 100

        // Remove one
        _sut.RemoveItem("GIZMO");
        // Total = 86

        // Apply coupon
        _sut.ApplyCoupon("SAVE10");
        // Total = 86 * 0.90 = 77.4

        Assert.AreEqual(77.4m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_DuplicateSku_UpdatesPrice()
    {
        // When adding duplicate SKU with different price, the price updates
        _sut.AddItem("SKU-001", 2, 10.00m);
        _sut.AddItem("SKU-001", 1, 15.00m);

        // 3 quantity × 15 price = 45
        Assert.AreEqual(45.00m, _sut.CalculateTotal());
    }
}

